     1→<?php
     2→// tests/Mapper/ContactMapperTest.php
     3→namespace Xav\XsaltoPdsFid\Tests\Mapper;
     4→
     5→use PHPUnit\Framework\TestCase;
     6→use Xav\XsaltoPdsFid\Mapper\ContactMapper;
     7→
     8→class ContactMapperTest extends TestCase
     9→{
    10→    private ContactMapper $mapper;
    11→
    12→    protected function setUp(): void
    13→    {
    14→        $this->mapper = new ContactMapper();
    15→    }
    16→
    17→    public function testMapsBasicContactAttributes(): void
    18→    {
    19→        $contact = [
    20→            'id' => '6q85iaor8ayw',
    21→            'attributes' => [
    22→                'LastName'  => 'STONE',
    23→                'FirstName' => 'LUKE',
    24→                'Email'     => 'luke_stone@hotmail.com',
    25→                'Address1'  => '60 Long Garden Walk',
    26→                'Address2'  => null,
    27→                'Address3'  => null,
    28→                'ZipCode'   => 'GU9 7HX',
    29→                'City'      => 'Farnham',
    30→                'Language'  => null,
    31→                'LASTMOVE'  => '2026-03-28 10:13:06',
    32→                'Balance'   => 360,
    33→                'created'   => '2019-03-30 10:08:43',
    34→            ],
    35→            'relationships' => [
    36→                'Country' => ['data' => ['type' => 'countries', 'id' => 'CH']],
    37→                'Resorts' => ['data' => [['type' => 'resorts', 'id' => 'LesGets']]],
    38→                'skiers'  => ['data' => []],
    39→            ],
    40→        ];
    41→
    42→        $row = $this->mapper->mapToRow($contact);
    43→
    44→        $this->assertSame('6q85iaor8ayw', $row['id']);
    45→        $this->assertSame('STONE', $row['lastname']);
    46→        $this->assertSame('LUKE', $row['firstname']);
    47→        $this->assertSame('luke_stone@hotmail.com', $row['email']);
    48→        $this->assertSame('60 Long Garden Walk', $row['address1']);
    49→        $this->assertNull($row['address2']);
    50→        $this->assertSame('GU9 7HX', $row['zipcode']);
    51→        $this->assertSame('Farnham', $row['city']);
    52→        $this->assertSame('CH', $row['country']);
    53→        $this->assertSame(360, $row['balance']);
    54→        $this->assertSame('2026-03-28 10:13:06', $row['lastmove']);
    55→        $this->assertNull($row['language']);
    56→        $this->assertSame('2019-03-30 10:08:43', $row['created']);
    57→    }
    58→
    59→    public function testMapsResortsAsJson(): void
    60→    {
    61→        $contact = [
    62→            'id' => 'test-id',
    63→            'attributes' => [],
    64→            'relationships' => [
    65→                'Resorts' => ['data' => [['type' => 'resorts', 'id' => 'LesGets']]],
    66→                'skiers'  => ['data' => []],
    67→            ],
    68→        ];
    69→
    70→        $row = $this->mapper->mapToRow($contact);
    71→
    72→        $this->assertSame('[{"type":"resorts","id":"LesGets"}]', $row['resorts']);
    73→    }
    74→
    75→    public function testMapsSkiersAsJson(): void
    76→    {
    77→        $skierData = [['id' => 'skier1', 'attributes' => ['LastName' => 'STONE']]];
    78→        $contact = [
    79→            'id' => 'test-id',
    80→            'attributes' => [],
    81→            'relationships' => ['skiers' => ['data' => $skierData]],
    82→        ];
    83→
    84→        $row = $this->mapper->mapToRow($contact);
    85→
    86→        $this->assertSame(json_encode($skierData), $row['skiers']);
    87→    }
    88→
    89→    public function testHandlesMissingRelationships(): void
    90→    {
    91→        $contact = [
    92→            'id' => 'test-id',
    93→            'attributes' => ['Balance' => '150'],
    94→            'relationships' => [],
    95→        ];
    96→
    97→        $row = $this->mapper->mapToRow($contact);
    98→
    99→        $this->assertNull($row['country']);
   100→        $this->assertNull($row['resorts']);
   101→        $this->assertNull($row['skiers']);
   102→        $this->assertSame(150, $row['balance']);
   103→    }
   104→}
